# https://youtu.be/ur6pi3L98kk"""GaussianBilateral, Total variation filter, Wavelet denoising filterShift invariant waveletAnisotropic diffusionNLM - SkimageNLM - opencvBM3D Block-matching and 3D filteringMarkov random fieldThe 3 top denoising algorithms for MRI denoising areNLM, Bilateral, block-match and 3D filtering (BM3D)Total variation (TV) also works great.Bilateral is slow and it probably works fine except it takes too muchtime to experiment with parameters."""import matplotlib.pyplot as pltimport pydicomdataset = pydicom.dcmread("../data/CT_small.dcm")img = dataset.pixel_arrayplt.imshow(img, cmap=plt.cm.bone)# Save as TIFFplt.imsave("../data/dcm_to_tiff_converted.tif",           img,           cmap='gray')# =========================================================# Gaussian Denoising# =========================================================from skimage import img_as_floatfrom skimage.metrics import peak_signal_noise_ratiofrom scipy import ndimage as ndfrom skimage import io# Load imagesnoisy_img = img_as_float(io.imread("../data/MRI_noisy.tiff"))ref_img = img_as_float(io.imread("../data/MRI_clean.tif"))# Gaussian smoothinggaussian_img = nd.gaussian_filter(noisy_img,                                  sigma=5)# Save resultplt.imsave("images/MRI_images/Gaussian_smoothed.tif",           gaussian_img,           cmap='gray')# =========================================================# PSNR Evaluation# =========================================================noise_psnr = peak_signal_noise_ratio(ref_img,                                     noisy_img)gaussian_cleaned_psnr = peak_signal_noise_ratio(ref_img,                                                gaussian_img)print("PSNR of noisy image =", noise_psnr)print("PSNR after Gaussian denoising =", gaussian_cleaned_psnr)# Higher PSNR = better image quality# =========================================================# Bilateral Filter# =========================================================from skimage.restoration import (    denoise_tv_chambolle,    denoise_bilateral,    denoise_wavelet,    estimate_sigma)sigma_est = estimate_sigma(noisy_img,                           multichannel=True,                           average_sigmas=True)denoise_bilateral_img = denoise_bilateral(    noisy_img,    sigma_spatial=15,    multichannel=False)bilateral_cleaned_psnr = peak_signal_noise_ratio(    ref_img,    denoise_bilateral_img)print("Bilateral PSNR =",      bilateral_cleaned_psnr)# Bilateral filter:# Preserves edges while reducing noise# =========================================================# Total Variation (TV) Denoising# =========================================================denoise_TV = denoise_tv_chambolle(    noisy_img,    weight=0.3,    multichannel=False)TV_cleaned_psnr = peak_signal_noise_ratio(    ref_img,    denoise_TV)print("TV PSNR =",      TV_cleaned_psnr)# TV denoising:# Removes noise while preserving sharp edges# =========================================================# Wavelet Denoising# =========================================================wavelet_smoothed = denoise_wavelet(    noisy_img,    multichannel=False,    method='BayesShrink',    mode='soft',    rescale_sigma=True)Wavelet_cleaned_psnr = peak_signal_noise_ratio(    ref_img,    wavelet_smoothed)print("Wavelet PSNR =",      Wavelet_cleaned_psnr)# Wavelet denoising:# Removes noise at multiple frequency scales# =========================================================# Shift Invariant Wavelet# =========================================================from skimage.restoration import cycle_spindenoise_kwargs = dict(    multichannel=False,    wavelet='db1',    method='BayesShrink',    rescale_sigma=True)Shft_inv_wavelet = cycle_spin(    noisy_img,    func=denoise_wavelet,    max_shifts=3,    func_kw=denoise_kwargs,    multichannel=False)shft_cleaned_psnr = peak_signal_noise_ratio(    ref_img,    Shft_inv_wavelet)print("Shift Invariant Wavelet PSNR =",      shft_cleaned_psnr)# Shift invariant wavelet:# Reduces wavelet artifacts caused by shifting# =========================================================# BM3D Denoising# =========================================================import bm3dBM3D_denoised_image = bm3d.bm3d(    noisy_img,    sigma_psd=0.2,    stage_arg=bm3d.BM3DStages.ALL_STAGES)BM3D_cleaned_psnr = peak_signal_noise_ratio(    ref_img,    BM3D_denoised_image)print("BM3D PSNR =",      BM3D_cleaned_psnr)# BM3D:# One of the best classical denoising algorithms# Uses:# 1. Block matching# 2. Grouping similar patches# 3. 3D collaborative filtering# =========================================================# MRF (Markov Random Field)# =========================================================# Very slow algorithm# Uses probabilistic graphical modeling# Idea:# Neighboring pixels are likely to have similar intensity# Energy minimization:# Choose pixel values that minimize total image energy# Main downside:# Computationally expensive# Often slower and weaker than BM3D# =========================================================# Important Concepts# =========================================================# sigma (Gaussian filter):# Controls blur strength# Larger sigma = stronger smoothing# PSNR:# Peak Signal-to-Noise Ratio# Higher = better denoising quality# MRI noise:# Often approximately Gaussian or Rician distributed# =========================================================# Recommended Practical Methods# =========================================================# Fast:# Gaussian# TV# Best classical performance:# BM3D# NLM# Edge-preserving:# Bilateral# TV# Research/advanced:# MRF# Anisotropic diffusion